mapper.update:
UPDATE conversation_do
SET last_message_at = #{lastMessageAt}
WHERE id = #{id}

mapper.select:
SELECT
FROM conversation_do c JOIN goods_do g ON g.id = c.goods_id JOIN users b ON b.id = c.buyer_id JOIN users s ON s.id = c.seller_id WHERE c.buyer_id = #{userId} UNION ALL SELECT
FROM conversation_do c JOIN goods_do g ON g.id = c.goods_id JOIN users b ON b.id = c.buyer_id JOIN users s ON s.id = c.seller_id WHERE c.seller_id = #{userId} AND c.seller_id != c.buyer_id ORDER BY conversation_last_message_at DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(1)
FROM (
    SELECT c.id FROM conversation_do c WHERE c.buyer_id = #{userId}
    UNION ALL
    SELECT c.id FROM conversation_do c WHERE c.seller_id = #{userId} AND c.seller_id != c.buyer_id
) AS combined

SELECT gi.goods_id AS goodsId, gi.image_url AS imageUrl FROM goods_image_do gi INNER JOIN ( SELECT goods_id, MIN(sort_order) AS min_sort, MIN(id) AS min_id FROM goods_image_do WHERE goods_id IN
#{id}
GROUP BY goods_id ) first ON gi.goods_id = first.goods_id AND gi.sort_order = first.min_sort AND gi.id = first.min_id
